import{_ as s,o,c as l,ai as a}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Logging","description":"","frontmatter":{"summary":"Logging surfaces, file logs, WS log styles, and console formatting","read_when":["Changing logging output or formats","Debugging CLI or gateway output"],"title":"Logging"},"headers":[],"relativePath":"gateway/logging.md","filePath":"gateway/logging.md","lastUpdated":null}'),i={name:"gateway/logging.md"};function t(n,e,r,c,d,g){return o(),l("div",null,[...e[0]||(e[0]=[a(`<h1 id="logging" tabindex="-1"><a class="header-anchor" href="#logging">#</a> Logging</h1><p>For a user-facing overview (CLI + Control UI + config), see <a href="/docs/logging">/logging</a>.</p><p>OpenSoul has two log “surfaces”:</p><ul><li><strong>Console output</strong> (what you see in the terminal / Debug UI).</li><li><strong>File logs</strong> (JSON lines) written by the gateway logger.</li></ul><h2 id="file-based-logger" tabindex="-1"><a class="header-anchor" href="#file-based-logger">#</a> File-based logger</h2><ul><li>Default rolling log file is under <code>/tmp/opensoul/</code> (one file per day): <code>opensoul-YYYY-MM-DD.log</code><ul><li>Date uses the gateway host&#39;s local timezone.</li></ul></li><li>The log file path and level can be configured via <code>~/.opensoul/opensoul.json</code>: <ul><li><code>logging.file</code></li><li><code>logging.level</code></li></ul></li></ul><p>The file format is one JSON object per line.</p><p>The Control UI Logs tab tails this file via the gateway (<code>logs.tail</code>). CLI can do the same:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --follow</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Verbose vs. log levels</strong></p><ul><li><strong>File logs</strong> are controlled exclusively by <code>logging.level</code>.</li><li><code>--verbose</code> only affects <strong>console verbosity</strong> (and WS log style); it does <strong>not</strong> raise the file log level.</li><li>To capture verbose-only details in file logs, set <code>logging.level</code> to <code>debug</code> or <code>trace</code>.</li></ul><h2 id="console-capture" tabindex="-1"><a class="header-anchor" href="#console-capture">#</a> Console capture</h2><p>The CLI captures <code>console.log/info/warn/error/debug/trace</code> and writes them to file logs, while still printing to stdout/stderr.</p><p>You can tune console verbosity independently via:</p><ul><li><code>logging.consoleLevel</code> (default <code>info</code>)</li><li><code>logging.consoleStyle</code> (<code>pretty</code> | <code>compact</code> | <code>json</code>)</li></ul><h2 id="tool-summary-redaction" tabindex="-1"><a class="header-anchor" href="#tool-summary-redaction">#</a> Tool summary redaction</h2><p>Verbose tool summaries (e.g. <code>🛠️ Exec: ...</code>) can mask sensitive tokens before they hit the console stream. This is <strong>tools-only</strong> and does not alter file logs.</p><ul><li><code>logging.redactSensitive</code>: <code>off</code> | <code>tools</code> (default: <code>tools</code>)</li><li><code>logging.redactPatterns</code>: array of regex strings (overrides defaults) <ul><li>Use raw regex strings (auto <code>gi</code>), or <code>/pattern/flags</code> if you need custom flags.</li><li>Matches are masked by keeping the first 6 + last 4 chars (length &gt;= 18), otherwise <code>***</code>.</li><li>Defaults cover common key assignments, CLI flags, JSON fields, bearer headers, PEM blocks, and popular token prefixes.</li></ul></li></ul><h2 id="gateway-websocket-logs" tabindex="-1"><a class="header-anchor" href="#gateway-websocket-logs">#</a> Gateway WebSocket logs</h2><p>The gateway prints WebSocket protocol logs in two modes:</p><ul><li><strong>Normal mode (no <code>--verbose</code>)</strong>: only “interesting” RPC results are printed: <ul><li>errors (<code>ok=false</code>)</li><li>slow calls (default threshold: <code>&gt;= 50ms</code>)</li><li>parse errors</li></ul></li><li><strong>Verbose mode (<code>--verbose</code>)</strong>: prints all WS request/response traffic.</li></ul><h3 id="ws-log-style" tabindex="-1"><a class="header-anchor" href="#ws-log-style">#</a> WS log style</h3><p><code>opensoul gateway</code> supports a per-gateway style switch:</p><ul><li><code>--ws-log auto</code> (default): normal mode is optimized; verbose mode uses compact output</li><li><code>--ws-log compact</code>: compact output (paired request/response) when verbose</li><li><code>--ws-log full</code>: full per-frame output when verbose</li><li><code>--compact</code>: alias for <code>--ws-log compact</code></li></ul><p>Examples:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># optimized (only errors/slow)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># show all WS traffic (paired)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ws-log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compact</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># show all WS traffic (full meta)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ws-log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> full</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="console-formatting-subsystem-logging" tabindex="-1"><a class="header-anchor" href="#console-formatting-subsystem-logging">#</a> Console formatting (subsystem logging)</h2><p>The console formatter is <strong>TTY-aware</strong> and prints consistent, prefixed lines. Subsystem loggers keep output grouped and scannable.</p><p>Behavior:</p><ul><li><strong>Subsystem prefixes</strong> on every line (e.g. <code>[gateway]</code>, <code>[canvas]</code>, <code>[tailscale]</code>)</li><li><strong>Subsystem colors</strong> (stable per subsystem) plus level coloring</li><li><strong>Color when output is a TTY or the environment looks like a rich terminal</strong> (<code>TERM</code>/<code>COLORTERM</code>/<code>TERM_PROGRAM</code>), respects <code>NO_COLOR</code></li><li><strong>Shortened subsystem prefixes</strong>: drops leading <code>gateway/</code> + <code>channels/</code>, keeps last 2 segments (e.g. <code>whatsapp/outbound</code>)</li><li><strong>Sub-loggers by subsystem</strong> (auto prefix + structured field <code>{ subsystem }</code>)</li><li><strong><code>logRaw()</code></strong> for QR/UX output (no prefix, no formatting)</li><li><strong>Console styles</strong> (e.g. <code>pretty | compact | json</code>)</li><li><strong>Console log level</strong> separate from file log level (file keeps full detail when <code>logging.level</code> is set to <code>debug</code>/<code>trace</code>)</li><li><strong>WhatsApp message bodies</strong> are logged at <code>debug</code> (use <code>--verbose</code> to see them)</li></ul><p>This keeps existing file logs stable while making interactive output scannable.</p>`,31)])])}const u=s(i,[["render",t]]);export{h as __pageData,u as default};
